import React from "react";
import { Swiper, SwiperSlide } from "swiper/react";
import { Autoplay, EffectFade, Pagination } from "swiper/modules";
import "swiper/css";
import "swiper/css/effect-fade";
import "swiper/css/pagination";
import "./Home.css";
import { useParams } from "react-router-dom";

function Home({ images }) {
  const { ProductId } = useParams(); // Get ProductId from URL parameters

  return (
    <>
      <Swiper
        className="home-swiper"
        autoplay={{ delay: 4000 }}
        effect="fade"
        pagination={{
          clickable: true,
          type: "bullets",
        }}
        style={{
          "--swiper-pagination-bullet-active": "#FFFFFF",
          "--swiper-pagination-bullet-active-color": "#ff0000", // Red
        }}
        modules={[EffectFade, Autoplay, Pagination]}
        loop={true}
      >
        {/* Ensure ProductId is valid and within bounds */}
        {images[ProductId] && (
          <SwiperSlide className="home-swiper-slide">
            <img
              src={images[ProductId].image}
              alt={`Product: ${images[ProductId].title}`}
            />
          </SwiperSlide>
        )}
      </Swiper>
    </>
  );
}

export default Home;



